import datetime
import sys
from pathlib import Path

# Asegura que el paquete `src/` esté en el path
ROOT = Path(__file__).resolve().parent
SRC = ROOT / "src"
if str(SRC) not in sys.path:
    sys.path.insert(0, str(SRC))

from DataAcquisitionModule.Domain.Entities.scrapedDocument import ScrapedDocument
from EmbbedingsModule.Infrastructure.newspaper_chunker import NewspaperChunker


def main():
    chunker = NewspaperChunker(max_tokens=400, overlap=80)

    document = ScrapedDocument(
        source="bbc",
        url="https://www.bbc.com/mundo/articles/ce352jv082no",
        url_normalized="https://www.bbc.com/mundo/articles/ce352jv082no",
        title="La disputa sobre quién debe pagar la defensa de Maduro en EE.UU. (y qué ha pasado en otros casos contra expresidentes extranjeros)",
        content="Una pregunta simple enfrenta en estos días al gobierno de Estados Unidos con Nicolás Maduro: ¿quién debe pagar la defensa del expresidente venezolano en Nueva York? Está previsto que la cuestión sea un tema crucial de la nueva comparecencia de Maduro ante un tribunal federal en Manhattan este jueves, en la fase inicial del proceso en su contra por cargos de narcotráfico que él rechaza. Maduro y su esposa, Cilia Flores, quien enfrenta cargos similares y también está presa en Nueva York, sostienen que su defensa debe ser costeada por el Estado venezolano. En cambio, el gobierno de EE.UU. afirma que esa posibilidad está vedada por las sanciones que aplica a Venezuela y que los acusados sólo podrían pagar sus defensas con fondos personales. Los costes de abogados elegidos en grandes casos como este pueden ascender a millones de dólares. Maduro y Flores niegan tener recursos propios para solventar su defensa y sus abogados han pedido al juez del caso, Alvin Hellerstein, que deje sin efecto las acusaciones porque creen que sus derechos fueron vulnerados. Expertos en derecho creen improbable que Hellerstein invalide este caso, que atrae la atención internacional desde que EE.UU. detuvo a Maduro y Flores en una operación militar relámpago en Caracas el 3 de enero. \"La solicitud de desestimar la acusación es absurda\", dice Ronald Allen, un profesor de derecho en la Universidad Northwestern experto en el proceso penal, a BBC Mundo. Pero la disputa sobre el pago de la defensa es vista como una señal temprana de los retos que plantea este gigantesco caso, con pocos precedentes como guía. \"Obligación de pagar\" Días después del arresto y trasladado de Maduro y Flores a Nueva York, sus abogados comenzaron a buscar que sus honorarios pudieran financiarse con fondos del gobierno venezolano. El 7 de enero pidieron autorización para eso a la Oficina de Control de Activos Extranjeros (OFAC, por sus siglas en inglés), una repartición del Tesoro de EE.UU. que aplica las sanciones económicas internacionales de Washington. El permiso de la OFAC es clave porque Maduro y el gobierno de Venezuela que encabezó de 2013 hasta su arresto están sancionados por señalamientos de corrupción, violaciones de derechos humanos, narcotráfico y otros crímenes. Fuente de la imagen, AFP via Getty Images Pie de foto, El gobierno venezolano aún considera a Maduro como presidente legítimo del país. Saltar Podcast y continuar leyendo Improbable El nuevo podcast de BBC Mundo sobre un amor que triunfó contra todo pronóstico Episodios Fin de Podcast El 9 de enero, la OFAC emitió los permisos solicitados para Maduro y Flores. Pero revirtió el primero menos de tres horas después y el segundo unas semanas más tarde. El abogado de Maduro, Barry Pollack, pidió en febrero al tribunal de Manhattan desestimar la acusación porque, a su entender, el gobierno de EE.UU. interfirió con el derecho a elegir la defensa que consagra la Sexta Enmienda de la Constitución. \"El gobierno de Venezuela, en virtud de sus leyes, tiene la obligación de pagar los gastos de defensa del señor Maduro\", afirmó. Para sostener eso, presentó la declaración de un jurista de Venezuela y señaló que el gobierno de este país \"está dispuesto a cumplir con su obligación de pagar los costos de la defensa\". La presidenta encargada de Venezuela, Delcy Rodríguez, ha dicho que Maduro aún es el \"presidente legítimo\" del país y que tanto él como Flores son inocentes. No obstante, Caracas y Washington restablecieron relaciones diplomáticas tras la captura de Maduro, en medio de varias presiones del gobierno de Donald Trump a Rodríguez. Fuente de la imagen, Getty Images Pie de foto, EE.UU. reanudó relaciones diplomáticas con Venezuela tras visitas como la del secretario de Interior, Doug Burgum, a la presidenta encargada Delcy Rodríguez. Pollack es un abogado con experiencia en grandes casos que en 2024 logró la liberación Julian Assange, el fundador de WikiLeaks que estaba acusado por EE.UU. de revelar información de seguridad nacional. Pero en su carta en defensa de Maduro, Pollack indicó que dejaría este caso si se mantienen las restricciones del Tesoro. \"Error administrativo\" Los fiscales respondieron que la habilitación inicial para que Maduro y Flores pagasen su defensa con fondos de Venezuela fue un \"error administrativo\" que se corrigió. \"La normativa de la OFAC prohíbe expresamente utilizar los fondos de una entidad sancionada para pagar los honorarios de los abogados de otra persona sancionada\", indicó un documento al tribunal el 13 de marzo firmado por Jay Clayton y otros fiscales. El documento niega que EE.UU. interfiera con el derecho a la defensa y señala que tanto Maduro como Flores pueden pagar sus abogados con recursos personales, pese a estar sancionados. También rechazaron que Maduro y Flores tengan derecho a prestaciones del gobierno venezolano porque, según EE.UU., \"no eran funcionarios ni empleados legítimos de Venezuela\". Fuente de la imagen, Bloomberg via Getty Images Pie de foto, El abogado Barry Pollack ha indicado que dejará de defender a Maduro si EE.UU. mantiene la prohibición de usar recursos de Venezuela para su defensa. La semana pasada, Pollack y el abogado de Flores, Mark Donnelly, reiteraron al juez que sus clientes carecen de recursos para pagar su defensa, como sostienen en una declaración jurada, y podrían presentar pruebas financieras. Además, negaron que una eventual designación de abogados de oficio para Maduro y Flores subsanaría la vulneración de derechos que a su entender supone prohibirles el acceso a fondos de Venezuela. El profesor Allen dice que una decisión de desestimar la acusación por eso como pide la defensa \"sólo ocurriría si el retraso en el acceso a los fondos causara algún perjuicio irreparable\". \"En este caso, si (Maduro) recibe los fondos podrá usarlos para sufragar los gastos de su defensa, lo que resuelve el problema\", agrega. Pero advierte que \"un acusado no tiene derecho a gastar el dinero de otras personas en su defensa\". \"Sin precedentes\" En EE.UU. hubo otros casos contra expresidentes extranjeros que tienen algunas similitudes con el de Maduro, pero también diferencias importantes. Tal vez el más parecido sea el proceso que EE.UU. llevó a cabo contra el expresidente de Panamá, Manuel Noriega, tras invadir el país y capturarlo en 1990 para ser juzgado por narcotráfico. El gobierno estadounidense negó inicialmente el acceso de Noriega a sus cuentas bancarias congeladas para pagar los costos de su defensa, estimados en millones de dólares. Pero los abogados de Noriega también indicaron que abandonarían el caso por falta de pagos y, tras un pulso con la fiscalía, alcanzaron un acuerdo avalado por el juez del caso para destinar parte de los recursos congelados a la defensa. El juicio se desarrolló en un tribunal federal de Miami y el general Noriega fue condenado en 1992. Fuente de la imagen, AFP via Getty Images Pie de foto, El expresidente panameño Manuel Noriega fue juzgado en EE.UU., un caso que guarda algunas semejanzas con el de Maduro. Más recientemente, el expresidente hondureño Juan Orlando Hernández fue extraditado a EE.UU. en 2022 para ser juzgado por narcotráfico en el mismo tribunal que tiene el caso de Maduro. La familia de Hernández indicó que su defensa se financiaría con recursos propios y donaciones. El expresidente también resultó condenado, pero en diciembre recibió un sorpresivo indulto de Trump y recuperó la libertad. Pero en ninguno de esos u otros casos previos los acusados eran considerados aún presidentes por el gobierno de su país al enfrentar la justicia de EE.UU., como ocurre con Maduro. Y esto comienza a generar complicaciones que seguramente seguirán en el proceso, advierte Chimène Keitner, una profesora de derecho internacional en la Universidad de California Davis. \"Nada impediría a Venezuela reembolsar a Maduro sus gastos legales en Venezuela, fuera de la jurisdicción de EE.UU.\", dice Keitner a BBC Mundo. \"Pero a los abogados que comparecen en tribunales estadounidenses se les debe pagar de forma compatible con las sanciones que se aplican\". A su juicio, si los derechos de Maduro bajo la Sexta Enmienda se vulneran por la prohibición de usar dinero venezolano en su defensa \"es sin duda una cuestión sin precedentes, dados los hechos tan inusuales de este caso\". Haz clic aquí para leer más historias de BBC News Mundo. Suscríbete aquí a nuestro nuevo newsletter para recibir cada viernes una selección de nuestro mejor contenido de la semana.",
        authors=["Juan Pérez"],
        date=datetime.datetime(2024, 3, 10),
    )

    # 3. aplicar chunking
    chunks = chunker.chunk(document)

    # 4. ver resultados
    print(f"Se generaron {len(chunks)} chunks:\n")

    for i, chunk in enumerate(chunks):
        print(f"Chunk {i}:")
        print(f"  id: {chunk.id}")
        print(f"  estimado tokens: {chunk.metadata['estimated_tokens']}")
        print(f"  texto:\n{chunk.content}\n")
        print("-" * 60)


if __name__ == "__main__":
    main()
